from __future__ import annotations
import json
from collections import defaultdict
from dataclasses import dataclass
from datetime import datetime, timezone

@dataclass
class ConsentAuditReport:
    generated_at: str
    period_start: str
    period_end: str
    total_subjects: int
    purpose_stats: dict[str, dict]   # purpose → {granted, withdrawn, active, stale_policy}
    chain_integrity: dict            # from verify_chain()
    oldest_policy_version_in_use: str

def generate_dpo_report(
    audit_log: ConsentAuditLog,
    current_policy_version: str,
    period_start: datetime,
    period_end: datetime,
) -> ConsentAuditReport:
    entries = [
        json.loads(line)
        for line in audit_log._path.read_text().splitlines()
        if line.strip()
    ]

    # Filter to reporting period
    in_period = [
        e for e in entries
        if period_start.isoformat() <= e["captured_at"] <= period_end.isoformat()
    ]

    subjects: set[str] = set()
    # purpose → {granted_count, withdrawn_count, stale_policy_count}
    stats: dict[str, dict] = defaultdict(lambda: {"granted": 0, "withdrawn": 0, "stale_policy": 0})
    oldest_version = current_policy_version

    for e in in_period:
        subjects.add(e["subject_id"])
        purpose = e["purpose"]
        if e["granted"]:
            stats[purpose]["granted"] += 1
        else:
            stats[purpose]["withdrawn"] += 1
        if e["policy_version"] != current_policy_version:
            stats[purpose]["stale_policy"] += 1
            if e["policy_version"] < oldest_version:
                oldest_version = e["policy_version"]

    chain_result = audit_log.verify_chain()

    return ConsentAuditReport(
        generated_at=datetime.now(timezone.utc).isoformat(),
        period_start=period_start.isoformat(),
        period_end=period_end.isoformat(),
        total_subjects=len(subjects),
        purpose_stats=dict(stats),
        chain_integrity=chain_result,
        oldest_policy_version_in_use=oldest_version,
    )
